const backendUrl = ($env.BACKEND_URL || 'http://host.docker.internal:8085').replace(/\/$/, '');
const secret = $env.N8N_AI_REVIEW_WEBHOOK_SECRET || '';
const extraRaw = $env.N8N_REPO_LIST || '';

async function fetchFromBackend() {
  if (!secret) return [];
  try {
    const res = await this.helpers.httpRequest({
      method: 'GET',
      url: `${backendUrl}/api/v1/webhooks/n8n/ai-review/legacy-repos`,
      headers: { 'X-N8N-Secret': secret },
      json: true,
      timeout: 30000,
    });
    return Array.isArray(res) ? res : [];
  } catch (e) {
    return [];
  }
}

function parseExtra(raw) {
  return raw
    .split(',')
    .map(s => s.trim())
    .filter(Boolean)
    .map(full => {
      const slash = full.indexOf('/');
      if (slash <= 0) return null;
      return { owner: full.slice(0, slash).trim(), repo: full.slice(slash + 1).trim() };
    })
    .filter(r => r && r.owner && r.repo);
}

function dedupe(items) {
  const seen = new Set();
  const out = [];
  for (const item of items) {
    const key = `${item.owner}/${item.repo}`.toLowerCase();
    if (seen.has(key)) continue;
    seen.add(key);
    out.push({ owner: item.owner, repo: item.repo });
  }
  return out;
}

const fromBe = await fetchFromBackend();
const fromBeMapped = fromBe.map(r => ({ owner: r.owner, repo: r.repo }));
const merged = dedupe([...fromBeMapped, ...parseExtra(extraRaw)]);

if (!merged.length) {
  throw new Error(
    'No repositories to review. Provision repos on the platform (status CREATED) or set N8N_REPO_LIST for extra test repos.'
  );
}

return merged.map(r => ({ json: r }));
